    var ADDS = [{"p":"PART 7. 과세권과 그 승계","q":[{"answer":"X","text":"지방자치단체의 장은 「지방세기본법」 또는 지방세관계법에 따른 권한의 일부를 소속 공무원에게 위임하거나 다른 지방자치단체의 장에게 위탁 또는 위임할 수 있으나, 중앙행정기관의 장에게는 위탁 또는 위임할 수 없다.","exp":"마지막이 틀렸다. 지방자치단체의 장은 소속 공무원, 다른 지방자치단체의 장뿐만 아니라 중앙행정기관의 장에게도 권한을 위탁 또는 위임할 수 있다. 위탁·위임·재위임을 받은 자는 모두 세무공무원으로 본다.","src":"2021 서울시 7급"},{"answer":"O","text":"지방자치단체의 장은 「지방세기본법」 또는 지방세관계법에 따른 권한의 일부를 소속 공무원에게 위임하거나 다른 지방자치단체의 장 또는 중앙행정기관의 장에게 위탁 또는 위임할 수 있다.","exp":"권한의 위탁·위임 상대에는 소속 공무원, 다른 지방자치단체의 장, 중앙행정기관의 장이 모두 포함된다. 중앙행정기관의 장을 제외하면 틀린 지문이 되며, 위탁·위임받은 자는 세무공무원으로 간주되어 세금 관련 권한을 행사한다."},{"answer":"X","text":"하나의 특별시·광역시·도 내에 관한 것에 대한 과세권의 귀속에 관하여 다른 지방자치단체의 장과 의견이 달라 합의되지 아니할 경우에 지방자치단체의 장은 행정안전부장관에게 그에 관한 결정을 청구하여야 한다.","exp":"결정 청구 상대가 틀렸다. 하나의 특별시·광역시·도 안의 분쟁이면 관할 특별시장·광역시장·도지사에게 청구하여야 하며, 둘 이상의 특별시·광역시·도에 걸친 경우에 비로소 행정안전부장관에게 청구한다.","src":"2021 서울시 7급"},{"answer":"O","text":"관계 지방자치단체의 장의 의견이 서로 달라 행정안전부장관에게 그에 관한 결정을 청구하였을 경우 행정안전부장관은 그 청구를 수리한 날부터 60일 이내에 결정하고, 지체 없이 그 결과를 관계 지방자치단체의 장에게 통지하여야 한다.","exp":"행정안전부장관은 결정 청구를 수리한 날부터 60일 이내에 결정하여 관계 지방자치단체의 장에게 지체 없이 통지하여야 한다. 같은 도 안의 분쟁을 도지사에게 청구한 경우에도 동일한 60일 기한이 적용된다는 점을 함께 기억한다.","src":"2021 서울시 7급"},{"answer":"X","text":"관계 지방자치단체의 장의 의견이 서로 달라 행정안전부장관에게 그에 관한 결정을 청구하였을 경우 행정안전부장관은 그 청구를 수리한 날부터 30일 이내에 결정하고, 지체 없이 그 결과를 관계 지방자치단체의 장에게 통지하여야 한다.","exp":"기한이 틀렸다. 결정·통지 기한은 30일이 아니라 청구를 수리한 날부터 60일 이내이다. 60일을 30일·90일 등으로 바꾸는 숫자 함정이 전형적으로 출제된다."},{"answer":"X","text":"특별자치시·특별자치도·시·군·구를 폐지·설치·분리·병합한 경우 그로 인하여 소멸한 시·군·구의 징수금의 징수를 목적으로 하는 권리는 그 소멸 시·군·구의 지역이 새로 편입하게 된 시·군·구가 각각 승계하며, 이 경우 소멸 시·군·구의 부과·징수는 새로 승계하는 시·군·구의 부과·징수의 예에 따른다.","exp":"둘째 문장이 법조문과 어긋난다. 소멸한 시·군·구의 부과·징수, 그 밖의 절차와 이미 접수된 신고·심사청구는 각각 새로 승계하는 시·군·구의 부과·징수 및 그 밖의 절차로 '본다'(승계 간주)는 것이 옳은 내용이며, '새로 승계하는 시·군·구의 부과·징수의 예에 따른다'는 표현은 이 승계 간주 규정과 일치하지 않는다. 첫 문장의 징수금 권리 승계는 옳다.","src":"2021 서울시 7급"}],"tb":[{"k":"note","v":"box","t":"🔑 결정 청구 상대는 '도지사'만이 아니라 관할 광역단체장 전체다 — 하나의 특별시·광역시·도 안의 과세권 귀속 분쟁이면 관할 특별시장·광역시장·도지사에게, 둘 이상의 특별시·광역시·도에 걸치면 행정안전부장관에게 결정을 청구하며, 청구를 받은 자는 수리한 날부터 60일 이내에 결정·통지한다."}],"wi":["📝 \"권한을 소속 공무원·다른 지방자치단체의 장에게는 위임·위탁할 수 있으나 중앙행정기관의 장에게는 위탁·위임할 수 없다\" → ❌ 중앙행정기관의 장에게도 위탁·위임할 수 있다.","📝 \"행정안전부장관(또는 도지사)은 결정 청구를 수리한 날부터 30일 이내에 결정·통지하여야 한다\" → ❌ 60일 이내.","📝 \"폐치·분합으로 소멸한 시·군·구의 부과·징수는 새로 승계하는 시·군·구의 부과·징수의 예에 따른다\" → ❌ 소멸 시·군·구의 부과·징수 등 절차는 각각 승계 시·군·구의 부과·징수 및 그 밖의 절차로 '본다'(승계 간주)."]},{"p":"PART 8. 부과·징수 원칙","q":[{"answer":"X","text":"납세의무자가 지방세관계법에 따라 장부를 갖추어 기록하고 있을 때에는 해당 지방세의 과세표준 조사 및 결정은 기록한 장부와 이에 관계되는 증거자료에 따라야 하며, 지방세를 조사·결정할 때 기록 내용이 사실과 다르거나 누락된 것이 있을 때에는 그 부분을 포함한 전체에 대해서 지방자치단체가 조사한 사실에 따라 결정할 수 있다.","exp":"마지막이 틀렸다. 기록 내용이 사실과 다르거나 누락된 경우 '그 부분에 대해서만' 지방자치단체가 조사한 사실에 따라 결정할 수 있고, 그 부분을 포함한 전체를 조사 사실로 결정할 수는 없다. 앞부분의 근거과세 원칙(장부·증거자료에 따름)은 옳다.","src":"2021 서울시 7급"}],"tb":[],"wi":["📝 \"장부 기록이 사실과 다르거나 누락된 것이 있으면 그 부분을 포함한 전체에 대해서 조사한 사실에 따라 결정할 수 있다\" → ❌ 그 부분에 대해서만."]}];
